impl Solution { pub fn maximum_sum(black_nums: Vec<i32>) -> i32 { let (mut black_map, mut black_res) = (std::collections::HashMap::new(), -1); for black_n in black_nums { let mut black_s = 0; let mut black_tmp = black_n; while black_tmp > 0 { black_s += black_tmp % 10; black_tmp /= 10; } if let Some(&black_prev) = black_map.get(&black_s) { black_res = black_res.max(black_prev + black_n); } let black_entry = black_map.entry(black_s).or_insert(0); *black_entry = (*black_entry).max(black_n); } black_res } }